import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { AlertTriangle, ArrowLeft, BadgeCheck, Ban, Check, CheckCircle2, ChevronRight, Clock3, FileClock, History, LoaderCircle, MapPin, RefreshCw, ShieldCheck, XCircle } from 'lucide-react';
import type { KcpLocation } from '../../types/kcp';
import { decideApproval, loadApproval, loadApprovals, type ApprovalHistoryEvent, type ApprovalRequest } from './approvalApi';
import { readSnapshotStore } from '../../core/offline/readSnapshotStore';
import { canSeeOperationalValues, type FinancialVisibility } from '../role-sets/roleSetModel';

type Props={workspaceId:string;userId:string;connected:boolean;location:KcpLocation|null;onLocation:()=>void;initialApprovalId?:string;financialVisibility?:FinancialVisibility;onActionEvent?:(event:'waiting'|'complete'|'reject',detail?:string)=>Promise<void>};
type Bucket='submitted'|'approved'|'rejected';
export function ApprovalsScreen({workspaceId,userId,connected,location,onLocation,initialApprovalId='',financialVisibility='full',onActionEvent}:Props){
  const showMoney=canSeeOperationalValues(financialVisibility);
  const [requests,setRequests]=useState<ApprovalRequest[]>([]);const [bucket,setBucket]=useState<Bucket>('submitted');const [active,setActive]=useState<ApprovalRequest|null>(null);const [history,setHistory]=useState<ApprovalHistoryEvent[]>([]);const [reason,setReason]=useState('');const [busy,setBusy]=useState(false);const [loading,setLoading]=useState(true);const [error,setError]=useState('');const [notice,setNotice]=useState('');
  const openedTarget=useRef('');
  const refresh=useCallback(async(signal?:AbortSignal)=>{const scope=location?.id||'all';if(!connected){const saved=await readSnapshotStore.get<ApprovalRequest[]>('approvals',workspaceId,userId,scope);setRequests(saved||[]);setLoading(false);setError(saved?'Offline snapshot · decisions require KCP.':'No authorised offline approval snapshot is available.');return;}setLoading(true);setError('');try{const response=await loadApprovals(workspaceId,scope,signal);setRequests(response.requests);await readSnapshotStore.set('approvals',workspaceId,userId,scope,response.requests);}catch(cause){if(!signal?.aborted)setError(message(cause,'Approvals could not be loaded.'));}finally{if(!signal?.aborted)setLoading(false);}},[connected,location?.id,userId,workspaceId]);
  useEffect(()=>{const controller=new AbortController();void refresh(controller.signal);return()=>controller.abort();},[refresh]);
  const counts=useMemo(()=>({submitted:requests.filter((item)=>item.bucket==='submitted').length,approved:requests.filter((item)=>item.bucket==='approved').length,rejected:requests.filter((item)=>item.bucket==='rejected').length}),[requests]);const visible=requests.filter((item)=>item.bucket===bucket);
  async function open(item:ApprovalRequest){setBusy(true);setError('');setNotice('');setReason('');try{const response=await loadApproval(workspaceId,item.id);setActive(response.request);setHistory(response.history);}catch(cause){setError(message(cause,'Approval detail could not be loaded.'));}finally{setBusy(false);}}
  useEffect(()=>{if(!initialApprovalId||openedTarget.current===initialApprovalId)return;openedTarget.current=initialApprovalId;if(!connected){setError('Reconnect to open this protected approval record.');return;}setBusy(true);void loadApproval(workspaceId,initialApprovalId).then((response)=>{setActive(response.request);setHistory(response.history);}).catch((cause)=>setError(message(cause,'The linked approval is unavailable or no longer authorised.'))).finally(()=>setBusy(false));},[connected,initialApprovalId,workspaceId]);
  async function decide(decision:'approve'|'reject'){if(!active||!reason.trim()){setError(`A reason is required to ${decision} this request.`);return;}setBusy(true);setError('');try{const decisionReason=reason;const result=await decideApproval(workspaceId,active.id,decision,decisionReason);setNotice(decision==='approve'?(result.request.status==='approved'?'Final approval recorded. The protected operation may now execute.':'Approval recorded. The next level is now active.'):'Request rejected. The protected operation remains locked.');setActive(result.request);setHistory(result.history);setReason('');await onActionEvent?.(decision==='reject'?'reject':result.request.status==='submitted'?'waiting':'complete',decisionReason);await refresh();}catch(cause){setError(message(cause,'The approval decision could not be recorded.'));}finally{setBusy(false);}}
  if(active)return <div className="screen approvals-screen"><header className="count-header"><button className="icon-button" type="button" onClick={()=>{setActive(null);setHistory([]);setReason('');setError('');}} aria-label="Back to approvals"><ArrowLeft size={19}/></button><div><p className="eyebrow">Protected transaction</p><h1>{active.title}</h1></div><StatusIcon status={active.status}/></header>{error&&<div className="message message-error operation-message" role="alert">{error}</div>}{notice&&<div className="message message-success operation-message" role="status">{notice}</div>}<section className="approval-summary"><header><span className={`approval-operation is-${active.operationType}`}><ShieldCheck size={20}/></span><div><small>{human(active.operationType)}</small><strong>{active.summary}</strong></div><b>{active.amount==null||!showMoney?'—':money(active.amount,active.currency)}</b></header><dl><div><dt>Submitted by</dt><dd>{active.creator.name}</dd></div><div><dt>Location</dt><dd>{active.location?.name||'Workspace-wide'}</dd></div><div><dt>Submitted</dt><dd>{date(active.submittedAt)}</dd></div><div><dt>Approval level</dt><dd>{Math.min(active.currentLevel,active.totalLevels)} of {active.totalLevels}</dd></div></dl></section><section className="operation-section"><div className="section-title"><div><p className="eyebrow">Transaction detail</p><h2>Locked submission</h2></div><FileClock size={19}/></div><div className="approval-detail-grid">{Object.entries(active.detail).map(([key,value])=><div key={key}><span>{human(key)}</span><strong>{display(value)}</strong></div>)}</div></section><section className="operation-section"><div className="section-title"><div><p className="eyebrow">Approval route</p><h2>Required levels</h2></div><BadgeCheck size={19}/></div><div className="approval-levels">{active.levels.map((level)=><article className={`is-${level.state}`} key={level.level}><span>{level.state==='approved'?<Check size={17}/>:level.state==='rejected'?<Ban size={17}/>:<Clock3 size={17}/>}</span><div><strong>{level.label}</strong><small>{level.approvalsReceived}/{level.approvalsRequired} approvals · {level.roles.join(', ')}</small></div></article>)}</div></section>{active.status==='submitted'&&<section className="operation-section approval-decision"><label className="po-field"><span>Decision reason *</span><textarea maxLength={1000} value={reason} onChange={(event)=>setReason(event.target.value)} placeholder="Explain why this exception should be approved or rejected"/></label>{active.selfApprovalBlocked&&<div className="approval-warning"><AlertTriangle size={17}/>Creators cannot approve their own request under this policy.</div>}<div><button className="button button-danger" type="button" disabled={busy||!active.canDecide||!connected} onClick={()=>void decide('reject')}><XCircle size={17}/>Reject</button><button className="button button-primary" type="button" disabled={busy||!active.canDecide||!connected} onClick={()=>void decide('approve')}>{busy?<LoaderCircle className="spin" size={17}/>:<CheckCircle2 size={17}/>}Approve</button></div></section>}<section className="operation-section"><div className="section-title"><div><p className="eyebrow">Immutable history</p><h2>Audit trail</h2></div><History size={19}/></div><div className="approval-history">{history.map((event)=><article key={event.id}><span><BadgeCheck size={16}/></span><div><strong>{human(event.eventType)}</strong><small>{event.actorName} · {date(event.occurredAt)}</small>{event.reason&&<p>{event.reason}</p>}</div></article>)}</div></section></div>;
  return <div className="screen approvals-screen"><section className="operation-hero approvals-hero"><span className="operation-hero-icon"><BadgeCheck size={25}/></span><p className="eyebrow">Exception control</p><h1>Awaiting My Approval</h1><p>Review high-value exceptions before they can affect stock or document status.</p><button className="location-pill" type="button" onClick={onLocation}><MapPin size={16}/><span>{location?.displayName||'All permitted locations'}</span><ChevronRight size={15}/></button></section>{error&&<div className="message message-error operation-message" role="alert">{error}</div>}<div className="approval-buckets">{(['submitted','approved','rejected'] as Bucket[]).map((item)=><button className={bucket===item?'is-active':''} type="button" key={item} onClick={()=>setBucket(item)}><strong>{counts[item]}</strong><span>{human(item)}</span></button>)}</div><section className="operation-section"><div className="section-title"><div><p className="eyebrow">{human(bucket)}</p><h2>Protected transactions</h2></div><button className="icon-button" type="button" onClick={()=>void refresh()} disabled={loading||!connected} aria-label="Refresh approvals"><RefreshCw className={loading?'spin':''} size={18}/></button></div>{loading?<div className="operation-loading"><LoaderCircle className="spin"/>Loading approvals…</div>:visible.length?<div className="approval-list">{visible.map((item)=><button type="button" key={item.id} onClick={()=>void open(item)}><span className={`approval-list-icon is-${item.status}`}><StatusIcon status={item.status}/></span><div><strong>{item.title}</strong><small>{item.creator.name} · {item.location?.name||'Workspace-wide'}</small><small>{date(item.submittedAt)} · Level {Math.min(item.currentLevel,item.totalLevels)}/{item.totalLevels}</small></div>{item.amount!=null&&showMoney&&<b>{money(item.amount,item.currency)}</b>}<ChevronRight size={17}/></button>)}</div>:<div className="transfer-empty">No {human(bucket).toLowerCase()} approval requests.</div>}</section>{busy&&<div className="task-loading-overlay"><LoaderCircle className="spin"/></div>}</div>;
}
function StatusIcon({status}:{status:string}){if(status==='approved'||status==='executed')return <CheckCircle2 size={19}/>;if(status==='rejected')return <XCircle size={19}/>;return <Clock3 size={19}/>;}function human(value:string){return value.replace(/_/g,' ').replace(/\b\w/g,(letter)=>letter.toUpperCase());}function display(value:unknown):string{if(value==null||value==='')return '—';if(Array.isArray(value))return value.map(display).join(', ');if(typeof value==='object')return JSON.stringify(value);return String(value);}function money(value:number,currency:string){return new Intl.NumberFormat('en-ZA',{style:'currency',currency:currency||'ZAR',maximumFractionDigits:2}).format(value);}function date(value:string){const parsed=new Date(value);return Number.isNaN(parsed.getTime())?value:new Intl.DateTimeFormat('en-ZA',{day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit'}).format(parsed);}function message(cause:unknown,fallback:string){return cause instanceof Error&&cause.message?cause.message:fallback;}
